import re

# Read synonyms and find shortest option for each word
synonym_map = {}
with open('synonyms.txt', 'r') as f:
    for line in f:
        words = [w.strip() for w in line.strip().split(',')]
        shortest = min(words, key=len)
        for word in words:
            synonym_map[word.lower()] = shortest.lower()

words_to_check = ['unusually', 'communicative', 'reserved', 'judgments', 'habit',
                  'natures', 'victim', 'quality', 'normal', 'unknown', 'hostile',
                  'levity', 'sign', 'revelation', 'revelations', 'terms', 'obvious',
                  'suppressions', 'hope', 'unsought']

print("Additional words that can be shortened:")
for word in words_to_check:
    if word.lower() in synonym_map:
        shortest = synonym_map[word.lower()]
        if len(shortest) < len(word):
            print(f"{word} ({len(word)}) -> {shortest} ({len(shortest)}) saves {len(word)-len(shortest)}")
        else:
            print(f"{word} ({len(word)}) -> {shortest} ({len(shortest)}) [same or longer]")

EOF
